// frontend/src/components/Quiz.js
import React, {useState} from "react";

export default function Quiz({items}) {
  const [answers, setAnswers] = useState({});
  const [showAnswers, setShowAnswers] = useState(false);

  if (!items || items.length === 0)
    return <p>No quiz questions generated.</p>;

  const updateAnswer = (i, val) => {
    setAnswers(prev => ({ ...prev, [i]: val }));
  };

  return (
    <div style={{marginTop:"10px"}}>
      {items.map((q, i) => (
        <div key={i} style={{
          marginBottom:"15px",
          padding:"10px",
          background:"white",
          border:"1px solid #e2e8ff",
          borderRadius:"8px"
        }}>
          <div style={{marginBottom:"6px"}}>
            <strong>Q{i+1}:</strong> {q.question}
          </div>

          <input
            type="text"
            value={answers[i] || ""}
            onChange={(e) => updateAnswer(i, e.target.value)}
            style={{
              width:"100%",
              padding:"8px",
              borderRadius:"6px",
              border:"1px solid #b4c3ff"
            }}
            placeholder="Your answer"
          />

          {showAnswers && (
            <div style={{marginTop:"5px", color:"#2563eb"}}>
              <small>Correct Answer: {q.answer}</small>
            </div>
          )}
        </div>
      ))}

      <button
        onClick={() => setShowAnswers(!showAnswers)}
        style={{
          background:"#2563eb",
          color:"white",
          padding:"8px 20px",
          borderRadius:"8px",
          border:"none",
          cursor:"pointer",
          marginTop:"10px",
          fontWeight:"600"
        }}
      >
        {showAnswers ? "Hide Answers" : "Show Answers"}
      </button>
    </div>
  );
}
